import React, { useState } from "react";
import toast from "react-hot-toast";
import axios from "axios";

const Payment = ({ appointmentId, onPaymentDone }) => {
  const [method, setMethod] = useState("jazzcash");
  const [file, setFile] = useState(null);
  const [paid, setPaid] = useState(false);
  const token = localStorage.getItem("token");

  const handlePaymentConfirm = async () => {
    if ((method === "jazzcash" || method === "easypaisa") && !file) {
      toast.error("Please upload payment screenshot");
      return;
    }

    try {
      const formData = new FormData();
      formData.append("method", method);
      if (file) formData.append("screenshot", file);

      await axios.patch(
        `http://localhost:5000/api/appointments/${appointmentId}/pay`,
        formData,
        {
          headers: {
            Authorization: `Bearer ${token}`,
            "Content-Type": "multipart/form-data",
          },
        }
      );

      setPaid(true);
      toast.success("Payment submitted, waiting for verification!");
      if (onPaymentDone) onPaymentDone();
    } catch (error) {
      toast.error("Payment failed! " + (error.response?.data?.message || ""));
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-md max-w-md mx-auto mt-6">
      <h2 className="text-2xl font-bold mb-4">Payment</h2>

      {paid ? (
        <p className="text-green-600 font-semibold">Payment submitted ✅</p>
      ) : (
        <>
          <p className="mb-4">Select a payment method:</p>

          <div className="flex gap-4 mb-4">
            {["jazzcash", "easypaisa", "physical"].map((m) => (
              <button
                key={m}
                className={`px-4 py-2 rounded ${
                  method === m
                    ? m === "jazzcash"
                      ? "bg-blue-600 text-white"
                      : m === "easypaisa"
                      ? "bg-green-600 text-white"
                      : "bg-indigo-600 text-white"
                    : "bg-gray-200 text-gray-700"
                }`}
                onClick={() => setMethod(m)}
              >
                {m.charAt(0).toUpperCase() + m.slice(1)}
              </button>
            ))}
          </div>

          {/* Payment Instructions */}
          <div className="mb-4 p-4 bg-gray-100 rounded">
            {method === "jazzcash" && (
              <>
                <p>
                  <strong>JazzCash:</strong> 0304-8510524
                </p>
                <p>
                  <strong>Account Title:</strong> Muhammad Jawad Raza
                </p>
              </>
            )}
            {method === "easypaisa" && (
              <>
                <p>
                  <strong>Easypaisa:</strong> 0304-8510524
                </p>
                <p>
                  <strong>Account Title:</strong> Muhammad Jawad Raza
                </p>
              </>
            )}
            {method === "physical" && (
              <p>Pay physically at the clinic during your appointment.</p>
            )}
          </div>

          {/* Screenshot upload for JazzCash/EasyPaisa */}
          {(method === "jazzcash" || method === "easypaisa") && (
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setFile(e.target.files[0])}
              className="mb-4"
            />
          )}

          <button
            onClick={handlePaymentConfirm}
            className="w-full bg-green-600 text-white py-2 rounded hover:bg-green-700"
          >
            Submit Payment
          </button>
        </>
      )}
    </div>
  );
};

export default Payment;
